1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: readonly Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const NEIGHBORS_TO_SURVIVE = 2;
10	const NEIGHBORS_TO_REPRODUCE = 3;
11	
12	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy] as Cell);
16	
17	const uniqueCells = (cells: Cell[]): Cell[] =>
18	  [...new Map(cells.map((cell) => [cellKey(cell), cell])).values()];
19	
20	export function nextGeneration(liveCells: Cell[]): Cell[] {
21	  const liveSet = new Set(liveCells.map(cellKey));
22	  const isLive = (cell: Cell): boolean => liveSet.has(cellKey(cell));
23	
24	  const countLiveNeighbors = (cell: Cell): number =>
25	    neighborsOf(cell).filter(isLive).length;
26	
27	  const candidates = uniqueCells([
28	    ...liveCells,
29	    ...liveCells.flatMap(neighborsOf),
30	  ]);
31	
32	  const isAliveNextGeneration = (cell: Cell): boolean => {
33	    const liveNeighbors = countLiveNeighbors(cell);
34	    const reproduces = liveNeighbors === NEIGHBORS_TO_REPRODUCE;
35	    const survives = liveNeighbors === NEIGHBORS_TO_SURVIVE && isLive(cell);
36	    return reproduces || survives;
37	  };
38	
39	  return candidates.filter(isAliveNextGeneration);
40	}
